scwin.onpageload = function() {

      const codeOptions = [
        { grpCd: "SD102", compID: " gr_results2:cntrWtCondCd" },  //결제상태 콤보에 공통코드셋팅처리. 
        { grpCd: "OP196", compID: " gr_results2:transCls" }
    ];


    $c.data.setCommonCode(codeOptions, scwin.commonCodeCallBack);

};

scwin.commonCodeCallBack = async function(){
    scwin.initValues();

  	//f_tabLocation(0);

	chk_retrvStpYn.checked = true;

    sbm_dcScKnd.action = "/ds.co.RetreiveDcScKndCMD.do"; 
    await $c.sbm.execute(sbm_dcScKnd);

};
scwin.sbm_dcScKnd_submitDone = function(){
    scwin.tr_retrieve2();
}


scwin.tr_retrieve2 = async function(){

    ds_retrieve2.set( "odrNo", scwin.v_odrNo); // 오더번호
	ds_retrieve2.set( "cntrSeq", scwin.v_cntrSeq); // 컨테이너seq
	ds_retrieve2.set( "wrkLobranCd", scwin.v_wrkLobranCd); // 작업점소
	ds_retrieve2.set( "reqClsCd", scwin.v_reqClsCd); // 요청구분
	ds_retrieve2.set( "transCls", scwin.v_transCls); // ON/BOB
	ds_retrieve2.set( "cntrSizCd", scwin.v_cntrSizCd); // 컨테이너SIZE
	ds_retrieve2.set( "cntrTypCd", scwin.v_cntrTypCd); // 컨테이너TYPE
	//ds_retrieve2.NaValue(0, "dptWrkPlCd") = data[7]; // 출발지
	//ds_retrieve2.NaValue(0, "arvWrkPlCd") = data[8]; // 도착지
	ds_retrieve2.set("reqDt", scwin.v_reqDt); // 요청일자
	ds_retrieve2.set( "reqHh", scwin.v_reqHh); // 요청시간
	ds_retrieve2.set( "reqDoorCd", scwin.v_reqDoorCd); // 요청door

    sbm_retrieve2.action =  "/ncall.tn.os.odrrslts.odrrslts.RetrieveCntrAllocWorkResultsCMD.do"
    await $c.sbm.execute(sbm_retrieve2);
}

scwin.initValues = function(){

    scwin.nowDt = WebSquare.date.getCurrentServerDate().substring(0, 8);

    scwin.memJson = $c.data.getMemInfo();

    scwin.lobranCd = $c.data.getParameter("lobranCd") ==null? "" : $c.data.getParameter("lobranCd") ;
    scwin.afterSaveRetrieveYN = "YES";
	scwin.v_odrNo =  $c.data.getParameter("data")[0] ==null? "" : $c.data.getParameter("data")[0] ;
	scwin.v_cntrSeq = $c.data.getParameter("data")[1] ==null? "" : $c.data.getParameter("data")[1] ;
	scwin.v_wrkLobranCd = $c.data.getParameter("data")[2] ==null? "" : $c.data.getParameter("data")[2] ;
	scwin.v_reqClsCd = $c.data.getParameter("data")[3] ==null? "" : $c.data.getParameter("data")[3] ;
    scwin.v_transCls = $c.data.getParameter("data")[4] ==null? "" : $c.data.getParameter("data")[4] ;
    scwin.v_cntrSizCd = $c.data.getParameter("data")[5] ==null? "" : $c.data.getParameter("data")[5] ;
    scwin.v_cntrTypCd = $c.data.getParameter("data")[6] ==null? "" : $c.data.getParameter("data")[6] ;
    scwin.v_reqDt = $c.data.getParameter("data")[7] ==null? "" : $c.data.getParameter("data")[7] ;
    scwin.v_reqHh = $c.data.getParameter("data")[8] ==null? "" : $c.data.getParameter("data")[8] ;
    scwin.v_reqDoorCd = $c.data.getParameter("data")[9] ==null? "" : $c.data.getParameter("data")[9] ;

    scwin.lobranCd = $c.data.getParameter("lobranCd") ==null? "" : $c.data.getParameter("lobranCd") ;
    scwin.odrNo = $c.data.getParameter("odrNo") ==null? "" : $c.data.getParameter("odrNo") ;
    // scwin.v_reqHh = $c.data.getParameter("wrkStDt") ==null? "" : $c.data.getParameter("wrkStDt") ;
    // scwin.v_reqDoorCd = $c.data.getParameter("cntrNo") ==null? "" : $c.data.getParameter("cntrNo") ;

	scwin.v_qryClsCd = 'N';
	scwin.v_cntrOdrNo = $c.data.getParameter("cntrOdrNo") ==null? "" : $c.data.getParameter("cntrOdrNo") ;

    if(scwin.wrkStDt == ""){
  		ed_dptIntendDd.setValue(scwin.nowDt);
		ed_dptIntendDd2.setValue(scwin.nowDt) ;
  	}else{
  		ed_dptIntendDd.setValue(scwin.wrkStDt);
		ed_dptIntendDd2.setValue(scwin.wrkEndDt);
  	}
  	if(scwin.lobranCd == ""){
        scwin.lobranCd = scwin.memJson.upperLobranCd;
  		//lc_lobranCd.BindColVal = "<%=loginDTO.getLoUpperLobranCd()%>";
//  		lc_vehclLobranCd.BindColVal = "<%=loginDTO.getLoUpperLobranCd()%>";
  	}else{
  		//lc_lobranCd.BindColVal = "<%=lobranCd%>";
//  		lc_vehclLobranCd.BindColVal = "<%=lobranCd%>";
  	}
	//lc_qryClsCd.BindColVal = "N";

	if(scwin.cntrNo != ""){
  		//lc_noClsCd.BindColVal = "C";
  		//ed_cntrOdrNo.Text = "<%=cntrNo%>";
  		//scwin.f_Retrieve();
  	}else if(scwin.odrNo != ""){
  		//lc_noClsCd.BindColVal = "O";
  		//em_cntrOdrNo.Text = "<%=odrNo%>";
  		//scwin.f_Retrieve();
  	}else{
  		//lc_noClsCd.BindColVal = "O";
  	}

    chk_retrvStpYn.setValue("0");
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function(retrieveYn){

    var preChecked = chk_retrvStpYn.getValue();
    if(chk_retrvStpYn.getValue() == "1"){
        chk_retrvStpYn.setValue("0");
        scwin.f_filter();
    }

    if(ds_results2.getModifiedData().length == 0 && ds_dcScList.getModifiedData().length == 0){
        $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    for (var i=0; i < ds_results2.getRowCount(); i++) {
        if (ds_results2.getCellData(i, "vehclClntNo") == ds_results2.getCellData(i, "bilgClntNo")) {
            $c.win.alert("오더의 청구거래처와 협력 운송업체가 동일한 경우 저장 할 수 없습니다.");
            return false;
        }
    } 

//if(lc_qryClsCd.BindColVal == "N"){
    for(var i=0; i<= ds_results2.getRowCount() ; i++){
        if(ds_results2.getCellData(i,"alloccarCls") == "N" ){
            if(ds_results2.getRowStatus(i) == "U"){ //update
                if(ds_results2.getCellData(i,"cntrWrkShapeCd") != "" ){
                    if(ds_results2.getCellData(i,"wrkStpCd") == "0002"){
                        if(ds_results2.getCellData(i+1,"wrkStpCd") == "0003" && ds_results2.getCellData(i+1,"vehclNo") != ""){
                            if(ds_results2.getCellData(i,"odrNo") == ds_results2.getCellData(i+1,"odrNo") && ds_results2.getCellData(i,"cntrSeq") == ds_results2.getCellData(i+1,"cntrSeq") ){
                                $c.win.alert("DOOR운송 배차시, BOBTAIL, ON-GROUND를 선택하고 배차할 때는 회수단계는 차량이 없어야 합니다.");
                                ds_results2.setCellData(i+1,"vehclNo", "");
                                ds_results2.setCellData(i+1,"vehclShortNo", "");

                                ds_results2.setCellData(i+1, "vehclClntNo", "");
                                ds_results2.setCellData(i+1, "vehclClntNm", "");
                                ds_results2.setCellData(i+1, "drvNm", "");
                                ds_results2.setCellData(i+1, "mpNo", "");
                                ds_results2.setCellData(i+1, "eqCd", "");
                                ds_results2.setCellData(i+1, "chassShortNo", "");
                                ds_results2.setCellData(i+1, "chassisEqCd", "");
                                ds_results2.setCellData(i+1, "chassisKndCd","");
                                ds_results2.setCellData(i+1, "chassisVehclNo", "");
                                return false;
                            }
                        }
                    }else if(ds_results2.getCellData(i,"wrkStpCd") == "0003"){
                        if(ds_results2.getCellData(i-1,"wrkStpCd") == "0002" && ds_results2.getCellData(i-1,"vehclNo") != "" && ds_results2.getCellData(i-1,"alloccarCls") == "N"){
                            if(ds_results2.getCellData(i,"odrNo") == ds_results2.getCellData(i-1,"odrNo") && ds_results2.getCellData(i,"cntrSeq") == ds_results2.getCellData(i-1,"cntrSeq") ){
                                $c.win.alert("DOOR회수 배차시, BOBTAIL, ON-GROUND를 선택하고 운송단계보다 먼저 배차할 수 없습니다.");
                                ds_results2.setCellData(i-1,"vehclNo", "");
                                ds_results2.setCellData(i-1,"vehclShortNo", "");
                                ds_results2.setCellData(i,"vehclNo", "");
                                ds_results2.setCellData(i,"vehclShortNo", "");
                                return false;
                            }
                        }
                    }else if(ds_results2.배차시(i,"wrkStpCd") == "0047"){
                        $c.win.alert("육송 단계는 BOBTAIL, ON-GROUND로 배차할 수 없습니다");
                        return false;
                    }
                }
                /*
                if(ds_results2.NameValue(i,"dcScAmt") > 0 ){
                    if(ds_results2.NameValue(i,"dcScNm") == ""){
                        alert("할인할증금액은 팝업을 띄워서 할인할증항목을 선택하고, 금액을 입력한 후, 저장하셔야 합니다");
                        return false;
                    }
                }
                */
            }//if
        }
    }//for
//}

//if(lc_qryClsCd.BindColVal == "Y"){
    for(var i=0; i<= ds_results2.getRowCount() ; i++){
        if(ds_results2.getCellData(i,"alloccarCls") == "Y" ){
            if(ds_results2.getRowStatus(i) == "U"){ //update
                if(ds_results2.getCellData(i,"cooperatorYn") == 1 ){
                    if(ds_results2.getCellData(i,"vehclNo") != ""){
                        $c.win.alert("컨테이너 "+ds_results2.getCellData(i,"cntrNo")+" 는 협력업체에서 이미 배차한 물량은 취소할 수 없습니다. \n협력업체에서 먼저 배차를 취소한 후 취소할 수 있습니다.");
                        return false;
                        break;
                    }
                }
            }//if
        }
        else {
            if("B" == ds_results2.getCellData(i, "reqClsCd") || "C" == ds_results2.getCellData(i, "reqClsCd")) {
                if(await $c.gus.cfIsNull(ds_results2.getCellData(i,"vehclNo")) && ! await $c.gus.cfIsNull(ds_results2.getCellData(i,"vehclClntNo"))){
                    $c.win.alert("미지정(컨테이너), 지정범위 요청 건은 협력업체 배차 불가 합니다.");
                    return false;
                    break;
                }
            }
        }
    }//for
//}

    ds_result3.removeAll();
    var newIndex = 0;

        ds_results2.sort( "odrWrkStpSeq", 1 );
    // for(var i= ds_results2.getRowCount()-1; i >=0; i--){
    //     ds_result3.setRowJSON(newIndex,  ds_results2.getRowJSON(i));
    //     ds_result3.modifyRowStatus(newIndex, ds_results2.getRowStatus(i));

    //     newIndex ++;
    // }
    // newIndex = 0;

    scwin.afterSaveRetrieveYN = retrieveYn;
    await $c.sbm.execute(sbm_save);
    //ds_result3.removeAll();

    if(preChecked == "1"){
        chk_retrvStpYn.setValue("1");
        scwin.f_filter();
    };
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    // if (! await $c.gus.cfCanOpenPopup(inObj, pairObj))
    //     return;

    // 짝이 되는 오브젝트의 값 제거
    await $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
       scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

scwin.retrieveCarKindCoClntInfo_tproCb = function(rtnList){

  $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm);

};

scwin.retrieveUserInfo_tproCb = function(rtnList){
    $c.gus.cfSetReturnValue(rtnList, ed_alloccarPicId, ed_alloccarPicNm);
};

scwin.retrieveChassisNo_tproC = function(rtnList){
    $c.gus.cfSetReturnValue(rtnList, ed_shortChassNo, hid_chassisNo); 
    hid_chassisEqCd.setValue(rtnList[4]);
    hid_chassisKndCd.setValue( rtnList[2]);
}

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {

    // 선언부
    var rtnList;  // 공통POP-UP -> 요청화면 
    switch (disGubun) {


        case 4:
            //document.getElementById("lobranCd").value = lc_lobranCd.BindColVal;
            //alert(document.getElementById("lobranCd").value +", "+ lc_lobranCd.BindColVal);
            // 협력업체(차량매입) 계약승인 조회
           // retrieveCarKindCoClntInfo_tpro
           ed_clnt.setSelectId('retrieveCarKindCoClntInfo_tpro');
            rtnList = await ed_clnt.cfCommonPopUp(scwin.retrieveCarKindCoClntInfo_tproCb	// XML상의 SELECT ID	
                                    ,pCode					// 화면에서의 ??? Code Element의	Value
                                    ,pName					// 화면에서의 ??? Name Element의	Value
                                    ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					// Title순서	
                                    ,null					// 보여주는 각 컬럼들의 폭	
                                    ,null				// 컬럼중에서 숨기는	컬럼 지정	
                                    , DsConstants.PCHS_CLNT_CLS_CD_HIRECAR				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                    ,null					// 윈도우 위치 Y좌표	
                                    ,null					// 윈도우 위치 X좌표
                                    ,null					// 중복체크여부	("F")
                                    ,pAllSearch					// 전체검색허용여부	("F")
                                    ,"협력업체,협력업체코드/명,"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    );

            //var rtnString = '';
            //for(var i=0; i<rtnList.length; i++){
            //	rtnString += i+"컬럼 : "+rtnList[i]+', ';
            //}

            /*20141118 황창기 협력업체 계약 관련 수정 원복 김병찬
            if(rtnList != null && rtnList[0] != "N/A"){	
                document.getElementById("lobranCd").value = rtnList[8];
                if(cfIsNull(rtnList[4]) || cfIsNull(rtnList[5])){
                    alert("협력업체계약 등록 후 사용 가능합니다!");
                    em_clntNo.Text = '';
                    em_clntNo.Focus();
                }else if(rtnList[7] != 'Y'){
                    alert("협력업체계약 승인 후 사용 가능합니다!");
                    em_clntNo.Text = '';
                    em_clntNo.Focus();
                }else if(rtnList[3] == 0){
                    alert("협력업체 계약기간 만료일입니다.\n금일 이후 배차가 제한되오니 계약 갱신 바랍니다.");
                    cfSetReturnValue(rtnList, em_clntNo, txt_clntNm);
                }else if(rtnList[2] == 'A'){
                    alert("협력업체 계약기간 만료가 "+rtnList[3]+"일 남았습니다.\n 기간 내 계약 갱신 하시기 바랍니다.");
                    cfSetReturnValue(rtnList, em_clntNo, txt_clntNm);
                }else if(rtnList[3] > 30){
                    cfSetReturnValue(rtnList, em_clntNo, txt_clntNm);
                }else if(rtnList[3] < 0){
                    alert("협력업체 계약기간이 만료 되었습니다.\n 계약 갱신 후 사용 가능합니다. ");
                    em_clntNo.Text = '';
                    em_clntNo.Focus();
                }
            }*/

            break;

        case 5:
            //배차담당자
            //retrieveUserInfo_tpro
            rtnList = cfCommonPopUp(scwin.retrieveUserInfo_tproCb		// XML상의 SELECT ID	
                                    ,pCode					// 화면에서의 ??? Code Element의	Value
                                    ,pName					// 화면에서의 ??? Name Element의	Value
                                    ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					// Title순서	
                                    ,null					// 보여주는 각 컬럼들의 폭	
                                    ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                    ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
