                                        ,null                   // 검색 결과  컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                        ,null                   // Title순서
                                        ,null                   // 보여주는 각 컬럼들의 폭
                                        ,null                   // 컬럼중에서 숨기는  컬럼 지정
                                        ,'C'                    // SQL절의 WHERE절에  원하는 조건을 선택함 MAX:8개까지 가능
                                        ,null                   // POP-UP뛰을때 원도우의  사용자 정의 폭
                                        ,null                   // POP-UP뛰을때 우도우의  사용자 정의 높이
                                        ,null                   // 윈도우 위치 Y좌표
                                        ,null                   // 윈도우 위치 X좌표
                                        ,null                   // 중복체크여부 ("F")
                                        ,'F'                    // 전체검색허용여부 ("F")
                                        ,null                   // POP-UP Window Title 검색어1,2   ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                        );

            break;			

            default:
            break;
    }
};

scwin.retrieveChassisNo_tproCb = function(rtnList){
    if(scwin.btn1 == true){


        $c.gus.cfSetReturnValue(rtnList, ed_shortChassNo, hid_chassisNo); 
                    hid_chassisEqCd.setValue(rtnList[4]);
                    hid_chassisKndCd.setValue(rtnList[2]);
        scwin.btn1 = false;
    } else {
        ds_results2.setCellData(scwin.rowChk, "chassShortNo", rtnList[0]);
        scwin.rowChk = "";
    }

}

scwin.retrieveChassisNo_tproCb2 = function(rtnList){


    $c.gus.cfSetGridReturnValue(rtnList, ds_results2, scwin.row, "chassShortNo", "");
    ds_results2.setCellData(scwin.row, "chassisEqCd", rtnList[4]);
    ds_results2.setCellData(scwin.row, "chassisKndCd", rtnList[2]);
    ds_results2.setCellData(scwin.row, "chassisVehclNo", rtnList[1]);
    ds_results2.setCellData(scwin.row, "chassShortNo", rtnList[0]);

    var vOdrNo = ds_results2.getCellData(scwin.row,"odrNo");
    var vCntrSeq = ds_results2.getCellData(scwin.row,"cntrSeq");
    var vChassisEqCd = ds_results2.getCellData(scwin.row,"chassisEqCd");
    var vChassisKndCd = ds_results2.getCellData(scwin.row,"chassisKndCd");
    var vChassShortNo = ds_results2.getCellData(scwin.row,"chassShortNo");
    var vChassisVehclNo = ds_results2.getCellData(scwin.row,"chassisVehclNo");

    for(var i=0; i<=ds_results2.getRowCount(); i++){
        if(vOdrNo == ds_results2.getCellData(i,"odrNo") && vCntrSeq == ds_results2.getCellData(i,"cntrSeq")){
        ds_results2.setCellData(i,"chassisEqCd", vChassisEqCd);
        ds_results2.setCellData(i,"chassisKndCd", vChassisKndCd);
        ds_results2.setCellData(i,"chassShortNo", vChassShortNo);
        ds_results2.setCellData(i,"chassisVehclNo", vChassisVehclNo);
        }
    }

    scwin.f_checkChasisNo(scwin.row);

};

