//-------------------------------------------------------------------------
// filter
//-------------------------------------------------------------------------
scwin.f_filter = function() {

   ds_results2.clearFilter(); // 필터 초기화

    var fn_colFilter = function(cellData, tmpParam, rowIdx){
        if(cellData == "Y"){
            return true;
        }
        return false;   // true면 표시, false면 제외
    };

    ds_results2.setColumnFilter(
        {type:'func', colIndex:'alloccarCls', key:fn_colFilter, condition:'and'}
    );

    ds_results2.reform()



    totalRows.setValue(ds_results2.getRowCount());
};

