//-------------------------------------------------------------------------
// function name : f_deleteRow
// function desc : 배차취소 버튼 누를때 실행
//-------------------------------------------------------------------------
scwin.f_deleteRow = function(){


    var row = ds_results2.getRowPosition();
    ds_results2.undoRow(row);
    if(ds_results2.getCellData(row, "alloccarCls") == "Y"){
        var preChecked = chk_retrvStpYn.getValue();
        if(chk_retrvStpYn.getValue() == "1"){
            chk_retrvStpYn.setValue("0");
            scwin.f_filter();
        }
        var unCheckedRow = ds_results2.getRowPosition();
        var delCnt = 0;
        for(var i=0; i<=ds_results2.getRowCount(); i++){
            /*
            if(ds_results2.NameValue(unCheckedRow, "transWrkIndictNo") == ds_results2.NameValue(i, "transWrkIndictNo")){
                if(ds_results2.NameValue(row, "alloccarCls") == "Y"){
                    //협력업체 배차 아닌경우
                    if(ds_results2.NameValue(i, "cooperatorYn") == 0){
                        ds_results2.NameValue(i, "vehclNo") = "";
                        ds_results2.NameValue(i, "vehclShortNo") = "";
                    }else{//협력업체배차인 경우
                        ds_results2.NameValue(i, "vehclClntNo") = "";
                        ds_results2.NameValue(i, "vehclShortNo") = "";
                    }
                    //ds_results.DeleteRow(i);
                }


            }//if
            */
            if("B" == ds_results2.getCellData(i, "reqClsCd") || "C" == ds_results2.getCellData(i, "reqClsCd")) {
                if((ds_results2.getOriginalCellData(unCheckedRow, "vehclNo") == ds_results2.getCellData(i, "vehclNo"))
                        && (ds_results2.getCellData(unCheckedRow, "wrkStpCd") == ds_results2.getCellData(i, "wrkStpCd"))
                        && delCnt < 1 ) {
                    if(ds_results2.getCellData(i, "alloccarCls") == "Y"){

                        //협력업체 배차 아닌경우
                        if(ds_results2.getCellData(i, "cooperatorYn") == 0){
                            ds_results2.setCellData(i, "vehclNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                            ds_results2.setCellData(i, "cntrWrkShapeCd", "");
                        }else{
                        //협력업체배차인 경우
                            ds_results2.setCellData(i, "vehclClntNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                            ds_results2.setCellData(i, "cntrWrkShapeCd", "");
                        }
                        //ds_results.DeleteRow(i);
                    }
                    delCnt++;
                }//if

                if((ds_results2.getOriginalCellData(unCheckedRow, "vehclNo") == ds_results2.getCellData(i, "vehclNo"))
                        && (ds_results2.getOriginalCellData(unCheckedRow, "wrkStpCd") != ds_results2.getCellData(i, "wrkStpCd"))
                        && delCnt < 2 ) {
                    if(ds_results2.getCellData(i, "alloccarCls") == "Y"){

                        //협력업체 배차 아닌경우
                        if(ds_results2.getCellData(i, "cooperatorYn") == 0){
                            ds_results2.setCellData(i, "vehclNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                            ds_results2.setCellData(i, "cntrWrkShapeCd", "");
                        }else{
                        //협력업체배차인 경우
                            ds_results2.setCellData(i, "vehclClntNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                            ds_results2.setCellData(i, "cntrWrkShapeCd", "");
                        }
                        //ds_results.DeleteRow(i);
                    }
                    delCnt++;
                }//if

            }
            else {
                if(ds_results2.getCellData(unCheckedRow, "transWrkIndictNo") == ds_results2.getCellData(i, "transWrkIndictNo")){
                    if(ds_results2.getCellData(i, "alloccarCls") == "Y"){
                        //협력업체 배차 아닌경우
                        if(ds_results2.getCellData(i, "cooperatorYn") == 0){
                            ds_results2.setCellData(i, "vehclNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                        }else{//협력업체배차인 경우
                            ds_results2.setCellData(i, "vehclClntNo", "");
                            ds_results2.setCellData(i, "vehclShortNo", "");
                        }
                        //ds_results.DeleteRow(i);
                    }
                }//if
            }
        }//for
        if(preChecked == "1"){
            chk_retrvStpYn.setValue("1");
            scwin.f_filter();
        }

    }//if
};

//-------------------------------------------------------------------------황창기
// function name : f_setVehclClntNoToChecked()
// function desc : 협력업체 지정 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_setVehclClntNoToChecked = function(){
    if(ed_clntNo.getValue() == ""){
        $c.win.alert("협력업체를 선택하여 주십시오");
        ed_clntNo.focus();
        return false;
    }
    //20141118 황창기 협력업체 계약 관련 수정 원복 김병찬
    //if(txt_clntNm.value == "" || txt_clntNm.value == ""){
    //	alert("협력업체를 선택하여 주십시오");
    //	em_clntNo.focus();
    //	return false;
    //}
    for(var i=0; i<= ds_results2.getRowCount() ; i++){

        if(ds_results2.getCellData(i, "chk") == 1 
            && ds_results2.getCellData(i, "vehclNo") == ""
            && (ds_results2.getCellData(i, "reqClsCd") == "A" || ds_results2.getCellData(i, "reqClsCd") == "D" )){ // 지정, 첫배차인경우 협력업체 배차 가능

            /*20141118 황창기 협력업체 계약 관련 수정 원복 김병찬
            if(document.getElementById("lobranCd").value != ds_results.NameValue(i, "wrkLobranCd")) {
                em_clntNo.Text = ''; 
                txt_clntNm.value = '';
                return false;
            }*/

            ds_results2.setCellData(i, "vehclClntNo", ed_clntNo.getValue());
            ds_results2.setCellData(i, "vehclClntNm", ed_clntNm.getValue());

            var v_odrNo = ds_results2.getCellData(i, "odrNo");
            var v_cntrSeq = ds_results2.getCellData(i, "cntrSeq");
            var v_vehclClntNo = ds_results2.getCellData(i, "vehclClntNo");

            for(var j=0; j<= ds_results2.getRowCount(); j++){
                if( ds_results2.getCellData(j, "vehclClntNo") != ""
                    && i != j 
                    && v_odrNo == ds_results2.getCellData(j, "odrNo")
                    && v_cntrSeq == ds_results2.getCellData(j, "cntrSeq") 
                    && v_vehclClntNo != ds_results2.getCellData(j, "vehclClntNo") ){

                    alert("같은 오더, 컨테이너에 운송단계를 각각 다른  협력업체로 지정하여 동시에 배차할 수 없습니다. \n 운송단계 배차한 후에 회수단계를 배차하여 주시기 바랍니다.");
                    ds_results2.setCellData(i, "vehclClntNo", "");
                    ds_results2.setCellData(i, "vehclClntNm", "");
                    ds_results2.setCellData(i, "chk", "0");
                    return false;
                    break;
                }
            }//for

        }
    }//for

};

