// function name : f_setVehclClntNoToChecked()
// function desc : 협력업체 지정 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_setVehclNoAndChassisToChecked = function(){
    if(ed_shortVhclNo.getValue() == "" && ed_shortChassNo.getValue() == ""){
        $c.win.alert("차량이나 샤시를 선택하여 주십시오");
        ed_shortVhclNo.focus();
        return false;
    }
    var chkCnt = 0;
    for(var i=0; i<= ds_results2.getRowCount(); i++){
        if(ds_results2.getCellData(i, "chk") == 1) {
            if(ds_results2.getCellData(i, "alloccarCls") == "N") {
                ds_results2.setCellData(i, "vehclShortNo", ed_shortVhclNo.getValue());
                ds_results2.setCellData(i, "vehclNo", hid_vehclNo.getValue());
                ds_results2.setCellData(i, "vehclClntNo", hid_vehclClntNo.getValue());
                ds_results2.setCellData(i, "vehclClntNm", hid_vehclClntNm.getValue());
                ds_results2.setCellData(i, "drvNm", hid_drvNm.getValue());
                ds_results2.setCellData(i, "mpNo", hid_mpNo.getValue());
                ds_results2.setCellData(i, "eqCd", hid_eqCd.getValue());
                ds_results2.setCellData(i, "pdaYn", hid_pdaYn.getValue());
                ds_results2.setCellData(i, "chassShortNo", ed_shortChassNo.getValue());
                ds_results2.setCellData(i, "chassisEqCd", hid_chassisEqCd.getValue());
                ds_results2.setCellData(i, "chassisKndCd", hid_chassisKndCd.getValue());
                scwin.f_checkChasisNo(i);
                chkCnt++;
            }
            else {
                ds_results2.setCellData(i, "chk", "0")
                //alert("이미 배차된 물량 입니다.");
            }
        }
    }
    if(chkCnt == 0){
        $c.win.alert("check된 물량이 없습니다. 원하는 물량을 체크한 후에 차량배정 버튼을 누르면 체크된 행에 차량과 샤시번호가 setting됩니다");
        return false;
    }
};
