            chk_retrvStpYn.setValue("1");
            //alert("yyy1::"+ds_results.CountRow);		
            scwin.f_filter();
            //alert("yyy2::"+ds_results.CountRow);		

        }
    }else{
        ds_results2.undoRow(row);
        return false;
    }
