scwin.f_workPathMod2 = async function() {

    if (ds_results2.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["대상물량"]); //"선택된 @이(가) 없습니다.";
        return;
    }

    var arrParam = new Array();

    if("B" == ds_results2.getCellData(ds_results2.getRowPosition(), "reqClsCd")
        || "C" == ds_results2.getCellData(ds_results2.getRowPosition(), "reqClsCd")) {
        arrParam[0] = ds_results2.getCellData(ds_results2.getRowPosition(), "odrNo"); //오더번호
        arrParam[1] = ds_cntrPerWrkPrst.getCellData(ds_cntrPerWrkPrst.getRowPosition(), "cntrSeq"); //컨테이너순번	
    }	
    else {
        arrParam[0] = ds_results2.getCellData(0, "odrNo"); //오더번호
        arrParam[1] = ds_results2.getCellData(0, "cntrSeq"); //컨테이너순번		
    }

    //arrParam[2] = lc_qryClsCd.BindColVal

    if(scwin.memJson.loUpperLobranCd == "4BB") {
        var pURL = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_27p.xml";
    }
    else {		
        var pURL = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_26p.xml";
    }

    let opts = {};
    let data = {};
    opts.popupName = "작업경로상세정보변경(컨테이너)";
    opts.width  = "1100";
    opts.height = "750";
    opts.id = "popInitAmt";
    opts.scrollbars = false;
    opts.type      = "browserPopup";
    data.whereAreYouFrom  = "T";
    let rtnList = await $c.win.openPopup(pURL, opts, arrParam); 


    //var rtnVal = window.showModalDialog(pURL,arrParam,"dialogWidth:930px; dialogHeight:570px");

    //작업단계경로가 변경될 팝업후 무조건 재조회를 한다.(데이터 오류를 막기 위하여)
    scwin.f_Retrieve2();
};

scwin.f_Retrieve2 = async function(){

    ds_retrieve2.set( "odrNo", scwin.v_odrNo); // 오더번호
	ds_retrieve2.set( "cntrSeq", scwin.v_cntrSeq); // 컨테이너seq
	ds_retrieve2.set( "wrkLobranCd", scwin.v_wrkLobranCd); // 작업점소
	ds_retrieve2.set( "reqClsCd", scwin.v_reqClsCd); // 요청구분
	ds_retrieve2.set( "transCls", scwin.v_transCls); // ON/BOB
	ds_retrieve2.set( "cntrSizCd", scwin.v_cntrSizCd); // 컨테이너SIZE
	ds_retrieve2.set( "cntrTypCd", scwin.v_cntrTypCd); // 컨테이너TYPE
	ds_retrieve2.set( "reqDt", scwin.v_reqDt); // 요청일자
	ds_retrieve2.set( "reqHh", scwin.v_reqHh); // 요청시간
	ds_retrieve2.set( "reqDoorCd",scwin.v_reqDoorCd); // 요청doo
    sbm_retrieve2.action = "/ncall.tn.os.odrrslts.odrrslts.RetrieveCntrAllocWorkResultsCMD.do";
     await $c.sbm.execute(sbm_retrieve2);

}
