//-------------------------------------------------------------------------
// 행삭제 버튼 클릭 - 배차된 물량의 회수 단계등 1row만 삭제하고 싶을 때
//-------------------------------------------------------------------------
scwin.f_delAllocatedRow = function() { 
    row = ds_results2.getRowPosition();
    if(ds_results2.getCellData(row,"alloccarCls") == "Y" ){
        //협력업체 배차 아닌경우
        if(ds_results2.getCellData(row, "cooperatorYn") == 0){
            ds_results2.setCellData(row, "vehclNo", "");
            ds_results2.setCellData(row, "vehclShortNo", "");
        }else{//협력업체배차인 경우
            ds_results2.setCellData(row, "vehclClntNo", "");
            ds_results2.setCellData(row, "vehclShortNo", "");
        }      
    }

};

