//-------------------------------------------------------------------------
// function name : f_checkChasisNo
// function desc : 샤시번호 1111 체크
//------------------------------------------------------------------------- 
scwin.f_checkChasisNo = function(row){


    if ((ds_results2.getCellData(row, "posnClsCd") =="W" || ds_results2.getCellData(row, "posnClsCd")=="J")
        && ds_results2.getCellData(row,"alloccarCls") == "N") {
        var vOdrNo = ds_results2.getCellData(row, "odrNo");
        var vCntrSeq = ds_results2.getCellData(row, "cntrSeq");

        if (ds_results2.getCellData(row, "chassShortNo") == "1111"){
            alert("위수탁/자차인경우 샤시가 1111 올수가 없습니다. TR에 지정된 TL을 입력하세요");

            ds_results2.setCellData(row, "chassShortNo", "");
            ds_results2.setCellData(row, "chassisEqCd", "");
            ds_results2.setCellData(row, "chassisKndCd", "");	
            ds_results2.setCellData(row, "chassisVehclNo", "");

            for(var i=0; i<=ds_results2.getRowCount(); i++){
            if(vOdrNo == ds_results2.getCellData(i, "odrNo") && vCntrSeq == ds_results2.getCellData(i, "cntrSeq") ){
                ds_results2.setCellData(i, "chassShortNo", "");
                ds_results2.setCellData(i, "chassisEqCd", "");
                ds_results2.setCellData(i, "chassisKndCd", "");
                ds_results2.setCellData(i, "chassisVehclNo", "");
            }
            }//for
        }
    }//if
}


//-------------------------------------------------------------------------
// function name : f_vehclPopup
// function desc : 차량조회
//------------------------------------------------------------------------- 
scwin.f_vehclPopup = async function(){

    let opts = {};
    let data = {};
    opts.width  = "825";
    opts.height = "560";
    opts.id = "popInitAmt";
    opts.title = "차량정보";
    opts.popupName = "차량정보";
    opts.scrollbars = false;
    opts.type      = "browserPopup";
    data.vehclShortNo      = ed_shortVhclNo.getValue();
    data.whereAreYouFrom  = "T";
    let rtnList = await $c.win.openPopup("/ui/tn/op/transwrkindict/cntr/tn_304_01_05p.xml", opts, data);  

    if(!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A"){
        ed_shortVhclNo.setValue(rtnList[0]);
        hid_vehclNo.setValue(rtnList[1]);
        hid_vehclClntNo.setValue(rtnList[7]);
        hid_vehclClntNm.setValue(rtnList[8]);
        hid_drvNm.setValue(rtnList[18]);
        hid_mpNo.setValue(rtnList[17]);
        hid_eqCd.setValue(rtnList[4]);
        hid_pdaYn.setValue(rtnList[19]);
    }

}


