scwin.chk_alloccarYn_onchange = function (info) {


    if(info.checked == true){

        ds_results2.clearFilter(); // 필터 초기화

        var fn_colFilter = function(cellData, tmpParam, rowIdx){
            if(cellData == "N"){
                return true;
            }
            return false;   // true면 표시, false면 제외
        };

        ds_results2.setColumnFilter(
            {type:'func', colIndex:'alloccarCls', key:fn_colFilter, condition:'and'}
        );

        ds_results2.reform();
        options ={}
        options.sortIndex = "cntrSeq cntrNo wrkStpCd";
        options.sortOrder = "1 1 1";
        ds_results2.multisort( options );
        totalRows.setValue(ds_results2.getRowCount());
    } else {
        ds_results2.clearFilter();
        ds_results2.reform();
        options ={}
        options.sortIndex = "cntrSeq cntrNo wrkStpCd";
        options.sortOrder = "1 1 1";
        ds_results2.multisort( options );
          totalRows.setValue(ds_results2.getRowCount());
    }
};

