		ds_retrieveDcSc.NameValue(1, "alloccarNo") = ds_results2.NameValue(ds_results2.RowPosition,"alloccarNo");
		ds_retrieveDcSc.NameValue(1, "alloccarSeq") = ds_results2.NameValue(ds_results2.RowPosition,"alloccarSeq");

		tr_retrieveDiscountSurcharge.Action = "/tn.os.odrrslts.odrrslts.RetrieveDiscountSurchargeCMD.do"; 
	    tr_retrieveDiscountSurcharge.Post();
	    */
	    //필터링을 적용한다
		//ds_dcScList.UseFilter = 1;
		//ds_dcScList.removeColumnFilterAll();
    };

    if(columnIndex == 23){
		if(ds_results2.getCellData(row, "combine") == 1){
			if(ds_results2.getCellData(row, "cmpstcrgNo") != ""){
				$c.win.alert("컨테이너"+ds_results2.getCellData(row, "cntrNo")+"는 이미 combine된 컨테이너입니다.");
				ds_results2.undoRow(row);
				return false;
			}
		}
	}

	var v_odrNo = ds_results2.getCellData(row, "odrNo");
	var v_cntrSeq = ds_results2.getCellData(row, "cntrSeq");
	var v_chk = ds_results2.getCellData(row, "chk");
	var v_reqNo = ds_results2.getCellData(row, "reqNo");
	var v_wrkStpCd = ds_results2.getCellData(row, "wrkStpCd");
	var v_cnt = 0;

	if(ds_results2.getCellData(row,"alloccarCls") == "Y" ) {
		ds_results2.setCellData(row, "chk", "0");
		ds_results2.setCellData(row, "scalYn", ds_results2.getCellData(row, "scalYn"));		
	}
	else {
		if("0047" != ds_results2.getCellData(row, "wrkStpCd")){
			for(var i=0; i<=ds_results2.getRowCount(); i++){
				if("B" == ds_results2.getCellData(i, "reqClsCd") || "C" == ds_results2.getCellData(i, "reqClsCd")) {
					if( i != row 
					    && v_wrkStpCd != ds_results2.getCellData(i, "wrkStpCd") 
					    && "0047" != ds_results2.getCellData(i, "wrkStpCd")
					    && v_cnt == 0 ){

					    if(ds_results2.getCellData(i,"alloccarCls") == "Y" ) {
							ds_results2.setCellData(i, "chk", "0");
						}
					    else {
					    	ds_results2.setCellData(i, "chk", v_chk) ;
					    	v_cnt++;
					    }

					}
				}
				else {
					if( i != row 
					    && v_odrNo == ds_results2.getCellData(i, "odrNo") 
					    && v_cntrSeq == ds_results2.getCellData(i, "cntrSeq") 
					    && "0047" != ds_results2.getCellData(i, "wrkStpCd") ){

					    if(ds_results2.getCellData(i,"alloccarCls") == "Y" ) {
							ds_results2.setCellData(i, "chk", "0");
						}
					    else {
					    	ds_results2.setCellData(i, "chk", v_chk);
					    }

					}
				}

			}//for
		}
	}

	if(columnIndex == 0) {
		if(ds_results2.getCellData(row,"alloccarCls") == "Y" ){
			gr_results2.setReadOnly("column",'vehclShortNo', true);
			gr_results2.setReadOnly("column", 'combine', true); 
			gr_results2.setReadOnly("column",'cntrWtCondCd', true);
			gr_results2.setReadOnly("column",'chassShortNo', true);
			gr_results2.setReadOnly("column",'cntrWrkShapeCd', true);
			gr_results2.setReadOnly("column",'pdaYn', true);
			gr_results2.setReadOnly("column",'chk', true);

			//버튼 
			//cfEnableObjects([ btn_transCopino, btn_delRow ]);
			$c.gus.cfDisableObjects([  btn_Open ]);

			//가용차량 데이터셋 초기화
			//ds_resultsVehcl. ;
		}else{
			gr_results2.setReadOnly("column",'vehclShortNo', false);
			gr_results2.setReadOnly("column",'combine',  false);
			gr_results2.setReadOnly("column",'cntrWtCondCd', false);
			gr_results2.setReadOnly("column",'chassShortNo', false);
			gr_results2.setReadOnly("column",'cntrWrkShapeCd', false);
			gr_results2.setReadOnly("column",'pdaYn', false);
			gr_results2.setReadOnly("column",'chk', false);

			//버튼 
			//cfDisableObjects([ btn_transCopino, btn_delRow ]);
			$c.gus.cfEnableObjects([  btn_Open ]);

			var tempTime = "";
			for(var i=0; i<=ds_results2.getRowCount(); i++){
				if(ds_results2.getCellData(i, "closeTime") != ""){
					tempTime = ds_results2.getCellData(i, "closeTime");
					tempTime = tempTime.substr(0,2)+"/"+tempTime.substr(2,2)+" "+tempTime.substr(4,2)+":"+tempTime.substr(6,2);
					ds_results2.setCellData(i, "closeTime", tempTime); 
				}
			}
		}
	}

	if(columnIndex == 16) {	
		if(ds_results2.columnIndex(row,"wrkStpCd") == "0002" ){
			if(ds_results2.columnIndex(row,"alloccarCls") == "N" ) {
				gr_results2.setReadOnly("column",'scalYn', false);
			}
			else {

                gr_results2.setReadOnly("column",'scalYn', true);
			}			
		}
		else {

           gr_results2.setReadOnly("column",'scalYn', true);
		}	
	}




};

