scwin.udc_clnt1_onblurCodeEvent = async function (row) {

    var changeV ="";

    if(ed_shortChassNo.getValue() == ""){

        changeV = ds_results2.getCellData(row, "chassShortNo");
        scwin.btn2 = true;
    } else {
        changeV =  ed_shortChassNo.getValue();
        scwin.btn1 = true;
    }

    await scwin.f_openCommonPopUp(7, changeV, '', 'T', 'T');
};

scwin.chk_retrvStpYn_onviewchange = function (info) {


     if(info.checked == true){

        //ds_results2.clearFilter(); // 필터 초기화

        var fn_colFilter = function(cellData, tmpParam, rowIdx){
            if(cellData != "0003"){
                return true;
            }
            return false;   // true면 표시, false면 제외
        };

        ds_results2.setColumnFilter(
            {type:'func', colIndex:'wrkStpCd', key:fn_colFilter, condition:'and'}
        );
        options ={}
        options.sortIndex = "cntrSeq cntrNo wrkStpCd";
        options.sortOrder = "1 1 1";
        ds_results2.multisort( options );
        ds_results2.reform();
        totalRows.setValue(ds_results2.getRowCount());
    } else {
        ds_results2.clearFilter();
        options ={}
        options.sortIndex = "cntrSeq cntrNo wrkStpCd";
        options.sortOrder = "1 1 1";
        ds_results2.multisort( options );
         ds_results2.reform();
          totalRows.setValue(ds_results2.getRowCount());
    }
};

scwin.gr_results2_onafteredit = async function (rowIndex, columnIndex, value) {

    var row =rowIndex;
    switch (columnIndex) {

		case 19:
			if(ds_results2.getCellData(row, "cntrWrkShapeCd") != ""){
				if(ds_results2.getCellData(row, "wrkStpCd") == "0002"){
					for(var i=0; i<=ds_results2.getRowCount(); i++){
						if(ds_results2.getCellData(row, "odrNo") == ds_results2.getCellData(i, "odrNo") 
						    && ds_results2.setCellData(row, "cntrSeq") == ds_results2.getCellData(i, "cntrSeq")
						    && ds_results2.setCellData(row, "vehclNo") == ds_results2.getCellData(i, "vehclNo")
						    && ds_results2.getCellData(i, "wrkStpCd") == "0003"){
						    ds_results2.setCellData(i, "vehclShortNo", "");
							ds_results2.setCellData(i, "vehclNo", "");
							ds_results2.setCellData(i, "vehclClntNo", "");
							ds_results2.setCellData(i, "vehclClntNm", "");
							ds_results2.setCellData(i, "drvNm", "");
							ds_results2.setCellData(i, "mpNo", "");
							ds_results2.setCellData(i, "eqCd", "");
							ds_results2.setCellData(i, "chassShortNo", "");
							ds_results2.setCellData(i, "chassisEqCd", "");
							ds_results2.setCellData(i, "chassisKndCd", "");
							ds_results2.setCellData(i, "chassisVehclNo", "");
							break;
						}
					}
				}else{

					await $c.win.alert("DOOR운송 단계만 선택할 수 있습니다.");
					ds_results2.undoRow(row);
                    ds_results2.setCellData(row, "cntrWrkShapeCd", " ");
					return false;
				}
			}else{
				ds_results2.setCellData(row, "vehclShortNo", "");
				ds_results2.setCellData(row, "vehclNo", "");
				ds_results2.setCellData(row, "vehclClntNo", "");
				ds_results2.setCellData(row, "vehclClntNm", "");
				ds_results2.setCellData(row, "drvNm", "");
				ds_results2.setCellData(row, "mpNo", "");
				ds_results2.setCellData(row, "eqCd", "");
				ds_results2.setCellData(row, "chassShortNo", "");
				ds_results2.setCellData(row, "chassisEqCd", "");
				ds_results2.setCellData(row, "chassisKndCd", "");
				ds_results2.setCellData(row, "chassisVehclNo", "");
			}
			break;

	}

    if(columnIndex == 14) {
        scwin.rowChk = rowIndex;
        scwin.udc_clnt1_onblurCodeEvent(rowIndex)

    }

};
